#!/usr/bin/env python3
"""Consolidated candidate scoring helper for Wang Hao.

Run from workspace root:
    python3 scripts/score_candidate.py

Prints valid JSON to stdout.
"""

from __future__ import annotations

import json
import re
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
INTERVIEW_PATH = ROOT / "interview-feedback-forms.md"
REGISTRY_PATH = ROOT / "analysis" / "discrepancy_registry.json"


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def extract_huang_lei_scores(interview_text: str) -> tuple[float, float]:
    section_match = re.search(
        r"## 面试官 3: 黄磊.*?(?=\n---\n\n\*面试反馈|\Z)",
        interview_text,
        flags=re.S,
    )
    if not section_match:
        raise ValueError("Could not find Huang Lei interview section")
    section = section_match.group(0)

    technical_match = re.search(r"\| 技术能力 \| ([0-9]+(?:\.[0-9]+)?) \|", section)
    leadership_match = re.search(r"\| \*\*领导力评估\*\* \| \*\*([0-9]+(?:\.[0-9]+)?)\*\* \|", section)
    if not technical_match or not leadership_match:
        raise ValueError("Could not find Huang Lei technical/leadership scores")

    return float(technical_match.group(1)), float(leadership_match.group(1))


def count_red_flags() -> int:
    with REGISTRY_PATH.open(encoding="utf-8") as f:
        registry = json.load(f)
    discrepancies = registry.get("discrepancies", [])
    if not isinstance(discrepancies, list):
        raise ValueError("discrepancy registry has invalid shape")
    return len(discrepancies)


def resume_accuracy_score(red_flags: int) -> float:
    """Simple dossier score: starts at 5 and subtracts 0.75 per substantiated concern."""
    return max(0.0, round(5.0 - (0.75 * red_flags), 1))


def main() -> None:
    interview_text = read_text(INTERVIEW_PATH)
    technical_score, leadership_score = extract_huang_lei_scores(interview_text)
    red_flags = count_red_flags()

    result = {
        "technical_score": technical_score,
        "leadership_score": leadership_score,
        "resume_accuracy_score": resume_accuracy_score(red_flags),
        "recommendation": "do not proceed to P7 offer before clarification of substantiated discrepancies; consider P6 senior IC only after clarification",
        "red_flags": red_flags,
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

